    public void setUp() throws Exception {
        output = new ByteArrayOutputStream();
        factory = new DefaultLoggingFactory(new LoggerContext(), new PrintStream(output));
    }
// ---
    @After
    public void tearDown() throws Exception {
        factory.stop();
